#include <stdio.h>

int add(int a, int b) { return a + b; }
int add3(int a, int b, int c) { return a + b + c; }
int add4(int a, int b, int c, int d) { return a + b + c + d; }

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        if (N == 2) {
            int a, b;
            scanf("%d %d", &a, &b);
            printf("%d\n", add(a, b));
        } else if (N == 3) {
            int a, b, c;
            scanf("%d %d %d", &a, &b, &c);
            printf("%d\n", add3(a, b, c));
        } else if (N == 4) {
            int a, b, c, d;
            scanf("%d %d %d %d", &a, &b, &c, &d);
            printf("%d\n", add4(a, b, c, d));
        }
    }
    return 0;
}

