#include <bits/stdc++.h>
using namespace std;

class Calculator {
public:
    int add(int a, int b) { return a + b; }
    int add(int a, int b, int c) { return a + b + c; }
    int add(int a, int b, int c, int d) { return a + b + c + d; }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        Calculator calc;
        if (N == 2) {
            int a, b; cin >> a >> b;
            cout << calc.add(a, b) << '\n';
        } else if (N == 3) {
            int a, b, c; cin >> a >> b >> c;
            cout << calc.add(a, b, c) << '\n';
        } else if (N == 4) {
            int a, b, c, d; cin >> a >> b >> c >> d;
            cout << calc.add(a, b, c, d) << '\n';
        }
    }
    return 0;
}

