import java.io.*;
import java.util.*;

public class Main {
    static int add(int a, int b) { return a + b; }
    static int add(int a, int b, int c) { return a + b + c; }
    static int add(int a, int b, int c, int d) { return a + b + c + d; }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            if (N == 2) {
                int a = Integer.parseInt(st.nextToken());
                int b = Integer.parseInt(st.nextToken());
                sb.append(add(a, b));
            } else if (N == 3) {
                int a = Integer.parseInt(st.nextToken());
                int b = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                sb.append(add(a, b, c));
            } else { // N == 4
                int a = Integer.parseInt(st.nextToken());
                int b = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                int d = Integer.parseInt(st.nextToken());
                sb.append(add(a, b, c, d));
            }
            if (t < T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def add(a, b):
    return a + b

def add3(a, b, c):
    return a + b + c

def add4(a, b, c, d):
    return a + b + c + d

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out_lines = []
    for i in range(1, T + 1):
        parts = list(map(int, data[i].split()))
        N = parts[0]
        nums = parts[1:]
        if N == 2:
            out_lines.append(str(add(nums[0], nums[1])))
        elif N == 3:
            out_lines.append(str(add3(nums[0], nums[1], nums[2])))
        else:  # N == 4
            out_lines.append(str(add4(nums[0], nums[1], nums[2], nums[3])))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

